@startuml
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #f0f0f0
  BorderColor black
  ArrowColor black
}
skinparam stereotypeCBackgroundColor #a8d5ba
skinparam stereotypeCBorderColor black

package "businessRules" {
  package "Entity" {
    class User {
      <<C>>
      email: string
      roles: array
      password: string
      firstname: string
      lastname: string
    }
    class Post {
      <<C>>
      title: string
      description: string
      createdAt: DateTimeInterface
    }
    class Picture {
      <<C>>
      name: string
      url: string
    }
  }
}

User "One" *-- "Many" Post : To
Post "One" *-- "Many" Picture : To

@enduml
